 24	import BarChart from '../legacy/bar-chart';
 25	import Graph from '../legacy/graph';
 26	import SingleStat from '../legacy/single-stat';
 27	import Table from '../legacy/table';
 28	import { useBoolean } from '../../hooks/useBoolean';
 29	import { useIsVisible } from '../../hooks/useIsVisible';
 30	import {
 31	  getMutlipleQueryBrowserUrl,
 32	  getLegacyObserveState,
 33	  usePerspective,
 34	} from '../../hooks/usePerspective';
 35	import KebabDropdown from '../../kebab-dropdown';
 36	import { MonitoringState } from '../../../reducers/observe';
 37	import { evaluateVariableTemplate } from './legacy-variable-dropdowns';
 38	import { Panel, Row } from './types';
 39	import { QueryParams } from '../../query-params';
 40	import { LoadingInline } from '../../console/console-shared/src/components/loading/LoadingInline';
 41	import { CustomDataSource } from '@openshift-console/dynamic-plugin-sdk-internal/lib/extensions/dashboard-data-source';
 42	import {
 43	  DataSource,
 44	  isDataSource,
 45	} from '@openshift-console/dynamic-plugin-sdk/lib/extensions/dashboard-data-source';
