 47	const QueryBrowserLink = ({
 48	  queries,
 49	  customDataSourceName,
 50	}: {
 51	  queries: Array<string>;
 52	  customDataSourceName: string;
 53	}) => {
 54	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 55	  const { perspective } = usePerspective();
 56	
 57	  const params = new URLSearchParams();
 58	  queries.forEach((q, i) => params.set(`query${i}`, q));
 59	  const [namespace] = useActiveNamespace();
 60	
 61	  if (customDataSourceName) {
 62	    params.set('datasource', customDataSourceName);
 63	  }
 64	
 65	  return (
 66	    <Link aria-label={t('Inspect')} to={getMutlipleQueryBrowserUrl(perspective, params, namespace)}>
 67	      {t('Inspect')}
 68	    </Link>
 69	  );
 70	};
 71	
 72	// Determine how many columns a panel should span. If panel specifies a `span`, use that. Otherwise
 73	// look for a `breakpoint` percentage. If neither are specified, default to 12 (full width).
 74	const getPanelSpan = (panel: Panel): number => {
 75	  if (panel.span) {
 76	    return panel.span;
 77	  }
 78	  const breakpoint = _.toInteger(_.trimEnd(panel.breakpoint, '%'));
 79	  if (breakpoint > 0) {
 80	    return Math.round(12 * (breakpoint / 100));
 81	  }
 82	  return 12;
 83	};
 84	
 85	const getPanelClassModifier = (panel: Panel): string => {
 86	  const span: number = getPanelSpan(panel);
 87	  switch (span) {
 88	    case 6:
 89	      return 'max-2';
 90	    case 2:
 91	    // fallthrough
 92	    case 4:
 93	    // fallthrough
 94	    case 5:
 95	      return 'max-3';
 96	    case 3:
 97	      return 'max-4';
 98	    default:
 99	      return 'max-1';
100	  }
101	};
