103	const Card: React.FC<CardProps> = React.memo(({ panel, perspective }) => {
104	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
105	
106	  const [namespace] = useActiveNamespace();
107	  const pollInterval = useSelector((state: MonitoringState) =>
108	    getLegacyObserveState(perspective, state)?.getIn(['dashboards', perspective, 'pollInterval']),
109	  );
110	  const timespan = useSelector((state: MonitoringState) =>
111	    getLegacyObserveState(perspective, state)?.getIn(['dashboards', perspective, 'timespan']),
112	  );
113	  const variables = useSelector((state: MonitoringState) =>
114	    getLegacyObserveState(perspective, state)?.getIn(['dashboards', perspective, 'variables']),
115	  );
116	
117	  const ref = React.useRef();
118	  const [, wasEverVisible] = useIsVisible(ref);
119	
120	  const [isError, setIsError] = React.useState<boolean>(false);
121	  const [dataSourceInfoLoading, setDataSourceInfoLoading] = React.useState<boolean>(true);
122	  const [customDataSource, setCustomDataSource] = React.useState<CustomDataSource>(undefined);
123	  const customDataSourceName = panel.datasource?.name;
124	  const [extensions, extensionsResolved] = useResolvedExtensions<DataSource>(isDataSource);
125	  const hasExtensions = !_.isEmpty(extensions);
126	
127	  const formatSeriesTitle = React.useCallback(
128	    (labels, i) => {
129	      const title = panel.targets?.[i]?.legendFormat;
130	      if (_.isNil(title)) {
131	        return _.isEmpty(labels) ? '{}' : '';
132	      }
133	      // Replace Prometheus labels surrounded by {{ }} in the graph legend label templates
134	      // Regex is based on https://prometheus.io/docs/concepts/data_model/#metric-names-and-labels
135	      // with additional matchers to allow leading and trailing whitespace
136	      return title.replace(
137	        /{{\s*([a-zA-Z_][a-zA-Z0-9_]*)\s*}}/g,
138	        (match, key) => labels[key] ?? '',
139	      );
140	    },
141	    [panel],
142	  );
143	  const [csvData, setCsvData] = React.useState([]);
144	
145	  const csvExportHandler = () => {
146	    let csvString = '';
147	    const result = {};
148	    const seriesNames = [];
149	    for (let i = 0; i < csvData.length; i++) {
150	      const query = csvData[i];
151	      for (const series of query) {
152	        if (!series[0]) {
153	          continue;
154	        }
155	        const name = formatSeriesTitle(series[0], i);
156	        seriesNames.push(name);
157	        if (!name) {
158	          continue;
159	        }
160	        if (!Array.isArray(series[1])) {
161	          continue;
162	        }
163	        for (const entry of series[1]) {
164	          const dateTime = entry.x.toISOString();
165	          const value = entry.y;
166	          if (!result[dateTime]) {
167	            result[dateTime] = {};
168	          }
169	          result[dateTime][name] = value;
170	        }
171	      }
172	    }
173	    const uniqueSeriesNames = new Set(seriesNames);
174	    const uniqueSeriesArray = Array.from(uniqueSeriesNames);
175	
176	    csvString = `DateTime,${uniqueSeriesArray.join(',')}\n`;
177	
178	    for (const dateTime in result) {
179	      const temp = [];
180	      for (const name of uniqueSeriesArray) {
181	        temp.push(result[dateTime][name]);
182	      }
183	      csvString += `${dateTime},${temp.join(',')}\n`;
184	    }
185	
186	    const blobCsvData = new Blob([csvString], { type: 'text/csv' });
187	    const csvURL = URL.createObjectURL(blobCsvData);
188	    const link = document.createElement('a');
189	    link.href = csvURL;
190	    link.download = `graphData.csv`;
191	    link.click();
192	  };
193	
194	  const dropdownItems = [
195	    <DropdownItem key="action" component="button" onClick={csvExportHandler}>
196	      {t('Export as CSV')}
197	    </DropdownItem>,
198	  ];
199	
200	  React.useEffect(() => {
201	    const getCustomDataSource = async () => {
202	      if (!customDataSourceName) {
203	        setDataSourceInfoLoading(false);
204	        setCustomDataSource(null);
205	      } else if (!extensionsResolved) {
206	        setDataSourceInfoLoading(true);
207	      } else if (hasExtensions) {
208	        const extension = extensions.find(
209	          (ext) => ext?.properties?.contextId === 'monitoring-dashboards',
210	        );
211	        const getDataSource = extension?.properties?.getDataSource;
212	        const dataSource = await getDataSource?.(customDataSourceName);
213	
214	        if (!dataSource || !dataSource.basePath) {
215	          setIsError(true);
216	          setDataSourceInfoLoading(false);
217	        } else {
218	          setCustomDataSource(dataSource);
219	          setDataSourceInfoLoading(false);
220	        }
221	      } else {
222	        setDataSourceInfoLoading(false);
223	        setIsError(true);
224	      }
225	    };
