279	        data-test={`${panel.title.toLowerCase().replace(/\s+/g, '-')}-chart`}
280	        data-test-id={panel.id ? `chart-${panel.id}` : undefined}
281	      >
282	        <CardHeader
283	          actions={{
284	            actions: (
285	              <>
286	                {!isLoading && (
287	                  <QueryBrowserLink queries={queries} customDataSourceName={customDataSourceName} />
288	                )}
289	                {panel.type === 'graph' && isThereCsvData() && (
290	                  <KebabDropdown dropdownItems={dropdownItems} />
291	                )}
292	              </>
293	            ),
294	            hasNoOffset: false,
295	          }}
296	          className="monitoring-dashboards__card-header"
297	        >
298	          <CardTitle>{panel.title}</CardTitle>
299	        </CardHeader>
300	        <CardBody className="monitoring-dashboards__card--dashboard">
301	          {isError ? (
302	            <>
303	              <RedExclamationCircleIcon /> {t('Error loading card')}
304	            </>
305	          ) : (
306	            <div className="monitoring-dashboards__card-body-content" ref={ref}>
307	              {isLoading || !wasEverVisible ? (
308	                <div className={panel.type === 'graph' ? 'query-browser__wrapper' : ''}>
309	                  <LoadingInline />
310	                </div>
311	              ) : (
312	                <>
