323	                      isStack={panel.stack}
324	                      pollInterval={pollInterval}
325	                      queries={queries}
326	                      showLegend={panel.legend?.show}
327	                      units={panel.yaxes?.[0]?.format}
328	                      onZoomHandle={handleZoom}
329	                      customDataSource={customDataSource}
330	                      perspective={perspective}
331	                      onDataChange={(data) => setCsvData(data)}
332	                    />
333	                  )}
334	                  {(panel.type === 'singlestat' || panel.type === 'gauge') && (
335	                    <SingleStat
336	                      panel={panel}
337	                      pollInterval={pollInterval}
338	                      query={queries[0]}
339	                      namespace={namespace}
340	                      customDataSource={customDataSource}
341	                    />
342	                  )}
343	                  {panel.type === 'table' && (
344	                    <Table
345	                      panel={panel}
346	                      pollInterval={pollInterval}
347	                      queries={queries}
348	                      namespace={namespace}
349	                      customDataSource={customDataSource}
350	                    />
351	                  )}
352	                </>
353	              )}
354	            </div>
355	          )}
356	        </CardBody>
357	      </PFCard>
358	    </div>
359	  );
