362	const PanelsRow: React.FC<PanelsRowProps> = ({ row, perspective }) => {
363	  const showButton = row.showTitle && !_.isEmpty(row.title);
364	
365	  const [isExpanded, toggleIsExpanded] = useBoolean(showButton ? !row.collapse : true);
366	
367	  const Icon = isExpanded ? AngleDownIcon : AngleRightIcon;
368	  const title = isExpanded ? 'Hide' : 'Show';
369	
370	  return (
371	    <div data-test-id={`panel-${_.kebabCase(row?.title)}`}>
372	      {showButton && (
373	        <Button
374	          aria-label={title}
375	          className="pf-v5-m-link--align-left"
376	          onClick={toggleIsExpanded}
377	          style={{ fontSize: 24 }}
378	          title={title}
379	          variant="plain"
380	        >
381	          <Icon />
382	          &nbsp;{row.title}
383	        </Button>
384	      )}
385	      {isExpanded && (
386	        <div className="monitoring-dashboards__row">
387	          {_.map(row.panels, (panel) => (
388	            <Card key={panel.id} panel={panel} perspective={perspective} />
389	          ))}
390	        </div>
391	      )}
392	    </div>
393	  );
394	};
395	
396	export const LegacyDashboard: React.FC<BoardProps> = ({ rows, perspective }) => (
397	  <>
398	    {_.map(rows, (row) => (
399	      <PanelsRow key={_.map(row.panels, 'id').join()} row={row} perspective={perspective} />
400	    ))}
401	  </>
402	);
403	
404	type BoardProps = {
405	  rows: Row[];
406	  perspective: Perspective;
407	};
408	
409	type CardProps = {
410	  panel: Panel;
411	  perspective: Perspective;
412	};
413	
414	type PanelsRowProps = {
415	  row: Row;
416	  perspective: Perspective;
417	};

